package pl.msurvival.bans;import org.bukkit.*;import org.bukkit.command.*;import org.bukkit.configuration.file.*;import org.bukkit.entity.*;import org.bukkit.event.*;import org.bukkit.event.player.*;import org.bukkit.plugin.java.JavaPlugin;import java.io.*;import java.util.*;public final class MSurvivalBans extends JavaPlugin implements Listener{private File f;private YamlConfiguration data;public void onEnable(){saveDefaultConfig();f=new File(getDataFolder(),"bans.yml");if(!f.exists())try{getDataFolder().mkdirs();f.createNewFile();}catch(Exception e){e.printStackTrace();}data=YamlConfiguration.loadConfiguration(f);Bukkit.getPluginManager().registerEvents(this,this);}public boolean onCommand(CommandSender s,Command c,String l,String[] a){if(!s.hasPermission("msurvival.bans.admin"))return true;if(c.getName().equalsIgnoreCase("msban")&&a.length>=2){String r=String.join(" ",Arrays.copyOfRange(a,1,a.length));data.set("bans."+a[0].toLowerCase()+".reason",r);save();Player p=Bukkit.getPlayerExact(a[0]);if(p!=null)p.kickPlayer(color(getConfig().getString("messages.banned").replace("%reason%",r)));}if(c.getName().equalsIgnoreCase("msunban")&&a.length>=1){data.set("bans."+a[0].toLowerCase(),null);save();}if(c.getName().equalsIgnoreCase("mskick")&&a.length>=2){Player p=Bukkit.getPlayerExact(a[0]);if(p!=null)p.kickPlayer(color(String.join(" ",Arrays.copyOfRange(a,1,a.length))));}return true;}@EventHandler public void pre(AsyncPlayerPreLoginEvent e){String r=data.getString("bans."+e.getName().toLowerCase()+".reason");if(r!=null)e.disallow(AsyncPlayerPreLoginEvent.Result.KICK_BANNED,color(getConfig().getString("messages.banned").replace("%reason%",r)));}private void save(){try{data.save(f);}catch(Exception e){e.printStackTrace();}}private String color(String t){return ChatColor.translateAlternateColorCodes('&',t==null?"":t);}}
